#include <stdio.h>
#include <stdlib.h>

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int* weights = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &weights[i]);
    }
    for (int i = 0; i < Q; i++) {
        int queryType;
        scanf("%d", &queryType);
        if (queryType == 1) {
            int I, X;
            scanf("%d %d", &I, &X);
            weights[I - 1] = X;
        } else if (queryType == 2) {
            int L, R;
            scanf("%d %d", &L, &R);
            int* temp = (int*) malloc((R - L + 1) * sizeof(int));
            for (int j = 0; j <= R - L; j++) {
                temp[j] = weights[L + j - 1];
            }
            for (int j = 0; j <= R - L; j++) {
                weights[L + j - 1] = temp[R - L - j];
            }
            free(temp);
        } else if (queryType == 3) {
            int L, R, W;
            scanf("%d %d %d", &L, &R, &W);
            int sum = 0;
            for (int j = L - 1; j < R; j++) {
                sum += weights[j];
            }
            if (sum >= W) {
                printf("Yes\n");
            } else {
                printf("No\n");
            }
        }
    }
    free(weights);
    return 0;
}

