code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const [N, Q] = readline().split(' ').map(Number);
const weights = readline().split(' ').map(Number);
for (let i = 0; i < Q; i++) {
    const [queryType, ...args] = readline().split(' ').map(Number);
    if (queryType === 1) {
        const [I, X] = args;
        weights[I - 1] = X;
    } else if (queryType === 2) {
        const [L, R] = args;
        const temp = weights.slice(L - 1, R);
        weights.splice(L - 1, R - L, ...temp.reverse());
    } else if (queryType === 3) {
        const [L, R, W] = args;
        const sumWeights = weights.slice(L - 1, R).reduce((a, b) => a + b, 0);
        if (sumWeights >= W) {
            console.log('Yes');
        } else {
            console.log('No');
        }
    }
}

